#define PF_COUNTER
#include "tools/nds32_pfcounter.h"

void hello_world() {
    printf("Hello, World!\n");
}

int main() {
    printf("Starting performance counter test...\n");

    // Run the function with perf counter measurement
    startPFM;
    hello_world();
    stopPFM;

    // Report the performance counter results
    readResult();

    return 0;
}

